// auth/tokenStorage.js - Secure Token Storage
// ============================================
import * as SecureStore from 'expo-secure-store';

const KEYS = {
  ACCESS_TOKEN: 'oauth_access_token',
  REFRESH_TOKEN: 'oauth_refresh_token',
  TOKEN_EXPIRY: 'oauth_token_expiry',
  ID_TOKEN: 'oauth_id_token',
};

export const TokenStorage = {
  async saveTokens({ accessToken, refreshToken, expiresIn, idToken }) {
    const expiryTime = Date.now() + expiresIn * 1000;

    await Promise.all([
      SecureStore.setItemAsync(KEYS.ACCESS_TOKEN, accessToken),
      SecureStore.setItemAsync(KEYS.TOKEN_EXPIRY, expiryTime.toString()),
      refreshToken
        ? SecureStore.setItemAsync(KEYS.REFRESH_TOKEN, refreshToken)
        : Promise.resolve(),
      idToken
        ? SecureStore.setItemAsync(KEYS.ID_TOKEN, idToken)
        : Promise.resolve(),
    ]);
  },

  async getAccessToken() {
    const [token, expiry] = await Promise.all([
      SecureStore.getItemAsync(KEYS.ACCESS_TOKEN),
      SecureStore.getItemAsync(KEYS.TOKEN_EXPIRY),
    ]);

    if (!token || !expiry) return null;

    // Check if token is expired (with 60s buffer)
    if (Date.now() >= parseInt(expiry, 10) - 60000) {
      return null; // Token expired, caller should refresh
    }

    return token;
  },

  async getRefreshToken() {
    return SecureStore.getItemAsync(KEYS.REFRESH_TOKEN);
  },

  async getIdToken() {
    return SecureStore.getItemAsync(KEYS.ID_TOKEN);
  },

  async isTokenExpired() {
    const expiry = await SecureStore.getItemAsync(KEYS.TOKEN_EXPIRY);
    if (!expiry) return true;
    return Date.now() >= parseInt(expiry, 10) - 60000;
  },

  async clearAll() {
    await Promise.all(
      Object.values(KEYS).map((key) => SecureStore.deleteItemAsync(key))
    );
  },
};


