import * as AuthSession from 'expo-auth-session';
import * as WebBrowser from 'expo-web-browser';
import OAuthConfig from './config';
import { generateCodeVerifier, generateCodeChallenge, generateState } from './pkce';
import { TokenStorage } from './tokenStorage';

WebBrowser.maybeCompleteAuthSession();

class OAuthService {
  constructor() {
    this._codeVerifier = null;
    this._state = null;
  }

  /**
   * Build the authorization URL with PKCE parameters
   */
  async buildAuthorizationUrl() {
    this._codeVerifier = await generateCodeVerifier();
    const codeChallenge = await generateCodeChallenge(this._codeVerifier);
    this._state = generateState();

    const params = new URLSearchParams({
      response_type: 'code',
      client_id: OAuthConfig.clientId,
      redirect_uri: OAuthConfig.redirectUri,
      scope: OAuthConfig.scopes.join(' '),
      state: this._state,
      code_challenge: codeChallenge,
      code_challenge_method: 'S256',
    });

    return `${OAuthConfig.authorizationEndpoint}?${params.toString()}`;
  }

  /**
   * Start the OAuth authorization flow using system browser
   */
  async authorize() {
    const authUrl = await this.buildAuthorizationUrl();

    const result = await WebBrowser.openAuthSessionAsync(
      authUrl,
      OAuthConfig.redirectUri
    );

    if (result.type !== 'success' || !result.url) {
      throw new OAuthError('Authorization was cancelled or failed', 'auth_cancelled');
    }

    const url = new URL(result.url);
    const code = url.searchParams.get('code');
    const returnedState = url.searchParams.get('state');
    const error = url.searchParams.get('error');

    if (error) {
      const errorDescription = url.searchParams.get('error_description') || error;
      throw new OAuthError(errorDescription, error);
    }

    // Validate state to prevent CSRF attacks
    if (returnedState !== this._state) {
      throw new OAuthError(
        'State mismatch — possible CSRF attack',
        'state_mismatch'
      );
    }

    if (!code) {
      throw new OAuthError('No authorization code received', 'no_code');
    }

    // Exchange code for tokens using PKCE (no client_secret needed!)
    const tokens = await this.exchangeCodeForTokens(code);
    await TokenStorage.saveTokens(tokens);

    return tokens;
  }

  /**
   * Exchange authorization code for tokens using PKCE
   * NO client_secret is sent — the code_verifier proves we're the same client
   */
  async exchangeCodeForTokens(authorizationCode) {
    const body = new URLSearchParams({
      grant_type: 'authorization_code',
      code: authorizationCode,
      redirect_uri: OAuthConfig.redirectUri,
      client_id: OAuthConfig.clientId,
      // PKCE: code_verifier replaces client_secret
      code_verifier: this._codeVerifier,
      // NOTE: No client_secret! This is the secure way for mobile apps.
    });

    const response = await fetch(OAuthConfig.tokenEndpoint, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
      },
      body: body.toString(),
    });

    if (!response.ok) {
      const errorData = await response.json().catch(() => ({}));
      throw new OAuthError(
        errorData.error_description || 'Token exchange failed',
        errorData.error || 'token_exchange_error'
      );
    }

    const data = await response.json();

    return {
      accessToken: data.access_token,
      refreshToken: data.refresh_token,
      expiresIn: data.expires_in,
      idToken: data.id_token,
      tokenType: data.token_type,
    };
  }

  /**
   * Refresh the access token
   * For confidential refresh operations, proxy through your backend
   */
  async refreshAccessToken() {
    const refreshToken = await TokenStorage.getRefreshToken();

    if (!refreshToken) {
      throw new OAuthError('No refresh token available', 'no_refresh_token');
    }

    // Option A: Direct PKCE refresh (if your auth server supports it)
    const body = new URLSearchParams({
      grant_type: 'refresh_token',
      refresh_token: refreshToken,
      client_id: OAuthConfig.clientId,
      // No client_secret needed for public clients with PKCE
    });

    const response = await fetch(OAuthConfig.tokenEndpoint, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
      },
      body: body.toString(),
    });

    if (!response.ok) {
      // If refresh fails, user needs to re-authenticate
      await TokenStorage.clearAll();
      const errorData = await response.json().catch(() => ({}));
      throw new OAuthError(
        errorData.error_description || 'Token refresh failed',
        errorData.error || 'refresh_error'
      );
    }

    const data = await response.json();
    const tokens = {
      accessToken: data.access_token,
      refreshToken: data.refresh_token || refreshToken,
      expiresIn: data.expires_in,
      idToken: data.id_token,
    };

    await TokenStorage.saveTokens(tokens);
    return tokens;
  }

  /**
   * Get a valid access token, refreshing if necessary
   */
  async getValidAccessToken() {
    let accessToken = await TokenStorage.getAccessToken();

    if (accessToken) {
      return accessToken;
    }

    // Token expired, try to refresh
    try {
      const tokens = await this.refreshAccessToken();
      return tokens.accessToken;
    } catch (error) {
      throw new OAuthError('Session expired, please log in again', 'session_expired');
    }
  }

  /**
   * Revoke tokens and clear storage
   */
  async logout() {
    try {
      const refreshToken = await TokenStorage.getRefreshToken();
      const accessToken = await TokenStorage.getAccessToken();

      // Revoke refresh token on the server
      if (refreshToken) {
        await fetch(OAuthConfig.revocationEndpoint, {
          method: 'POST',
          headers: {
            'Content-Type': 'application/x-www-form-urlencoded',
          },
          body: new URLSearchParams({
            token: refreshToken,
            token_type_hint: 'refresh_token',
            client_id: OAuthConfig.clientId,
          }).toString(),
        }).catch(() => {}); // Best effort
      }

      // Revoke access token
      if (accessToken) {
        await fetch(OAuthConfig.revocationEndpoint, {
          method: 'POST',
          headers: {
            'Content-Type': 'application/x-www-form-urlencoded',
          },
          body: new URLSearchParams({
            token: accessToken,
            token_type_hint: 'access_token',
            client_id: OAuthConfig.clientId,
          }).toString(),
        }).catch(() => {}); // Best effort
      }
    } finally {
      await TokenStorage.clearAll();
    }
  }
}

class OAuthError extends Error {
  constructor(message, code) {
    super(message);
    this.name = 'OAuthError';
    this.code = code;
  }
}

export { OAuthError };
export default new OAuthService();


