// auth/AuthContext.js - React Context for Auth State
// ============================================
import React, { createContext, useContext, useEffect, useReducer, useCallback } from 'react';
import oauthService, { OAuthError } from './oauthService';
import { TokenStorage } from './tokenStorage';

const AuthContext = createContext(null);

const initialState = {
  isAuthenticated: false,
  isLoading: true,
  user: null,
  error: null,
};

function authReducer(state, action) {
  switch (action.type) {
    case 'RESTORE_TOKEN':
      return {
        ...state,
        isAuthenticated: true,
        isLoading: false,
        user: action.payload.user,
      };
    case 'SIGN_IN':
      return {
        ...state,
        isAuthenticated: true,
        isLoading: false,
        user: action.payload.user,
        error: null,
      };
    case 'SIGN_OUT':
      return {
        ...state,
        isAuthenticated: false,
        isLoading: false,
        user: null,
        error: null,
      };
    case 'SET_LOADING':
      return {
        ...state,
        isLoading: action.payload,
      };
    case 'SET_ERROR':
      return {
        ...state,
        error: action.payload,
        isLoading: false,
      };
    case 'LOADED':
      return {
        ...state,
        isLoading: false,
      };
    default:
      return state;
  }
}

function decodeJwtPayload(token) {
  try {
    const base64Url = token.split('.')[1];
    const base64 = base64Url.replace(/-/g, '+').replace(/_/g, '/');
    const jsonPayload = decodeURIComponent(
      atob(base64)
        .split('')
        .map((c) => '%' + ('00' + c.charCodeAt(0).toString(16)).slice(-2))
        .join('')
    );
    return JSON.parse(jsonPayload);
  } catch {
    return null;
  }
}

export function AuthProvider({ children }) {
  const [state, dispatch] = useReducer(authReducer, initialState);

  // Check for existing session on app launch
  useEffect(() => {
    async function restoreSession() {
      try {
        const accessToken = await oauthService.getValidAccessToken();
        if (accessToken) {
          const idToken = await TokenStorage.getIdToken();
          const user = idToken ? decodeJwtPayload(idToken) : null;
          dispatch({ type: 'RESTORE_TOKEN', payload: { user } });
        } else {
          dispatch({ type: 'LOADED' });
        }
      } catch {
        dispatch({ type: 'LOADED' });
      }
    }

    restoreSession();
  }, []);

  const signIn = useCallback(async () => {
    dispatch({ type: 'SET_LOADING', payload: true });
    try {
      const tokens = await oauthService.authorize();
      const user = tokens.idToken ? decodeJwtPayload(tokens.idToken) : null;
      dispatch({ type: 'SIGN_IN', payload: { user } });
    } catch (error) {
      const message =
        error instanceof OAuthError
          ? error.message
          : 'Authentication failed. Please try again.';
      dispatch({ type: 'SET_ERROR', payload: message });
      throw error;
    }
  }, []);

  const signOut = useCallback(async () => {
    dispatch({ type: 'SET_LOADING', payload: true });
    try {
      await oauthService.logout();
    } finally {
      dispatch({ type: 'SIGN_OUT' });
    }
  }, []);

  const getAccessToken = useCallback(async () => {
    return oauthService.getValidAccessToken();
  }, []);

  const value = {
    ...state,
    signIn,
    signOut,
    getAccessToken,
  };

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
}

export function useAuth() {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
}


