import React, { useEffect, useState } from 'react';
import {
  View,
  Text,
  TouchableOpacity,
  StyleSheet,
  SafeAreaView,
  Alert,
  ScrollView,
  ActivityIndicator,
} from 'react-native';
import { useAuth } from '../auth/AuthContext';
import apiClient from '../auth/apiClient';

export default function HomeScreen() {
  const { signOut, user, isLoading } = useAuth();
  const [profile, setProfile] = useState(null);
  const [profileLoading, setProfileLoading] = useState(true);

  useEffect(() => {
    loadProfile();
  }, []);

  const loadProfile = async () => {
    setProfileLoading(true);
    try {
      const data = await apiClient.get('/user/profile');
      setProfile(data);
    } catch (error) {
      console.log('Profile load error:', error.message);
      // Fall back to ID token claims
      if (user) {
        setProfile({
          name: user.name || user.preferred_username || 'User',
          email: user.email || '',
        });
      }
    } finally {
      setProfileLoading(false);
    }
  };

  const handleSignOut = () => {
    Alert.alert('Sign Out', 'Are you sure you want to sign out?', [
      { text: 'Cancel', style: 'cancel' },
      {
        text: 'Sign Out',
        style: 'destructive',
        onPress: async () => {
          try {
            await signOut();
          } catch (error) {
            Alert.alert('Error', 'Failed to sign out. Please try again.');
          }
        },
      },
    ]);
  };

  const displayName =
    profile?.name || user?.name || user?.preferred_username || 'User';
  const displayEmail = profile?.email || user?.email || '';

  return (
    <SafeAreaView style={styles.container}>
      <ScrollView contentContainerStyle={styles.scrollContent}>
        <View style={styles.header}>
          <Text style={styles.greeting}>Welcome back,</Text>
          <Text style={styles.userName}>
            {profileLoading ? '...' : displayName}
          </Text>
          {displayEmail ? (
            <Text style={styles.userEmail}>{displayEmail}</Text>
          ) : null}
        </View>

        <View style={styles.card}>
          <Text style={styles.cardTitle}>🔒 Security Info</Text>
          <View style={styles.cardRow}>
            <Text style={styles.cardLabel}>Auth Method</Text>
            <Text style={styles.cardValue}>OAuth 2.0 + PKCE</Text>
          </View>
          <View style={styles.cardRow}>
            <Text style={styles.cardLabel}>Client Type</Text>
            <Text style={styles.cardValue}>Public (no secret)</Text>
          </View>
          <View style={styles.cardRow}>
            <Text style={styles.cardLabel}>Token Storage</Text>
            <Text style={styles.cardValue}>Secure Keychain</Text>
          </View>
        </View>

        <View style={styles.card}>
          <Text style={styles.cardTitle}>📱 Quick Actions</Text>

          <TouchableOpacity
            style={styles.actionButton}
            onPress={loadProfile}
            activeOpacity={0.7}
          >
            {profileLoading ? (
              <ActivityIndicator size="small" color="#4361ee" />
            ) : (
              <Text style={styles.actionButtonText}>Refresh Profile</Text>
            )}
          </TouchableOpacity>

          <TouchableOpacity
            style={styles.actionButton}
            onPress={() => Alert.alert('API Call', 'This would make an authenticated API call')}
            activeOpacity={0.7}
          >
            <Text style={styles.actionButtonText}>Test API Call</Text>
          </TouchableOpacity>
        </View>

        <TouchableOpacity
          style={styles.signOutButton}
          onPress={handleSignOut}
          disabled={isLoading}
          activeOpacity={0.8}
        >
          {isLoading ? (
            <ActivityIndicator color="#dc3545" size="small" />
          ) : (
            <Text style={styles.signOutButtonText}>Sign Out</Text>
          )}
        </TouchableOpacity>
      </ScrollView>
    </SafeAreaView>
  );
}

